        b'-' | b'(' | b')' | b';' | b',' | b'=' | b'*' | b'~' | b'<' | b'>' | b'!' | b'&' | b'|' | b'+' | b'%' | b'/' => {
            i = 1;
            if (c == b'<' || c == b'>' || c == b'!' || c == b'=') && *z.offset(1) == b'=' {
                i = 2;
            }
            if c == b'<' && *z.offset(1) == b'>' {
                i = 2;
            }
