                i = 2;
                loop {
                    if *z.offset(i as isize) == 0 {
                        break;
                    }
                    if *z.offset(i as isize) == b'*' as u8 && *z.offset((i + 1) as isize) == b'/' as u8 {
                        i += 2;
                        break;
                    }
                    i += 1;
                }
            }
            return i;
        }
        b'"' | b'\'' | b'`' => {
            let quote = c;
            i = 1;
            loop {
                if *z.offset(i as isize) == quote {
                    i += 1;
                    if *z.offset(i as isize) != quote {
                        break;
                    }
                    i += 1;
                } else if *z.offset(i as isize) == 0 {
                    break;
                } else {
                    i += 1;
                }
            }
            return i;
        }
        b'[' => {
            i = 1;
            loop {
                if *z.offset(i as isize) == b']' as u8 {
                    i += 1;
                    break;
                } else if *z.offset(i as isize) == 0 {
                    break;
                } else {
                    i += 1;
                }
            }
            return i;
        }
        _ => {
            i = 1;
            while *z.offset(i as isize) != 0 {
                let ch = *z.offset(i as isize);
                if (ch as u8).is_ascii_alphanumeric() || ch == b'_' as u8 {
                    i += 1;
                } else {
                    break;
                }
            }
            return i;
        }
    }
}

