pub extern "C" fn strContainsChar(zStr: *const u8, nStr: i32, ch: u32) -> i32 {
    if nStr <= 0 || zStr.is_null() {
        return 0;
    }

    unsafe {
        let z_end = zStr.wrapping_add(nStr as usize);
        let mut z = zStr;

        while (z as usize) < (z_end as usize) {
            let tst = *z as u32;
            z = z.wrapping_add(1);
            if tst == ch {
                return 1;
            }
        }
    }

    0
}

