pub extern "C" fn vdbeSorterTreeDepth(nPMA: i32) -> i32 {
    let mut nDepth: i32 = 0;
    let mut nDiv: i64 = 16;
    while nDiv < (nPMA as i64) {
        nDiv = nDiv.wrapping_mul(16);
        nDepth = nDepth.wrapping_add(1);
    }
    nDepth
}

